/**
 * Legacy origin-airports list. Consumers that only need the 10 original home airports
 * can keep importing ORIGIN_AIRPORTS. Everyone else should use INTERNATIONAL_AIRPORTS.
 */
const ORIGIN_CODES = new Set(['MCO', 'JFK', 'LAX', 'SFO', 'ORD', 'SEA', 'LHR', 'CDG', 'YYZ', 'SYD']);
export const ORIGIN_AIRPORTS: Airport[] = INTERNATIONAL_AIRPORTS
  .filter((a) => ORIGIN_CODES.has(a.iata))
  .map((a) => ({ code: a.iata, city: a.city, country: a.country, lat: a.lat, lon: a.lon }));

// ---- Lookup helpers ----

const _byIata = new Map<string, InternationalAirport>();
for (const a of INTERNATIONAL_AIRPORTS) _byIata.set(a.iata, a);

const _byRegion = new Map<string, InternationalAirport[]>();
for (const a of INTERNATIONAL_AIRPORTS) {
  const list = _byRegion.get(a.region) ?? [];
  list.push(a);
  _byRegion.set(a.region, list);
}

/** Find an airport by its IATA code. O(1). */
export function getAirport(iata: string): InternationalAirport | undefined {
  return _byIata.get(iata.toUpperCase());
}

/** Get all airports in a given region. */
export function getAirportsByRegion(region: InternationalAirport['region']): InternationalAirport[] {
  return _byRegion.get(region) ?? [];
}

/** Search airports by query string (matches IATA, name, city, or country, case-insensitive). */
export function searchAirports(query: string): InternationalAirport[] {
  const q = query.toLowerCase();
  return INTERNATIONAL_AIRPORTS.filter(
    (a) =>
      a.iata.toLowerCase().includes(q) ||
      a.name.toLowerCase().includes(q) ||
      a.city.toLowerCase().includes(q) ||
      a.country.toLowerCase().includes(q),
  );
}

/** Legacy compat: find by code (same as getAirport but returns Airport type). */
export function findAirport(code: string): Airport | undefined {
  const a = getAirport(code);
  if (!a) return undefined;
  return { code: a.iata, city: a.city, country: a.country, lat: a.lat, lon: a.lon };
}
